(154, 'Student Microscopes', '153', NULL, NULL, 0, 'Student Microscope', NULL, '583165student-microscope-500x500.jpg', 'student-microscopes', '<div><strong><h2>Students Microscope Manufacturer, Suppliers, and Exporters</h2></strong></div><div><br></div><div>We are a&nbsp;<strong>Students Microscope manufacturer and supplier&nbsp;</strong>worldwide. Clients, who were searching for good quality as well as cost-efficient products are invited to contact us.\nWe have the entire range of <strong><a href=\"https://aticolabexport.com/category/laboratory-microscopes\" title=\"\" target=\"\">Laboratory Microscopes</a></strong>. Our suppliers will provide you the best range within the required time frame.\nYou can visit our official website aticoexport.com for more details. It is an eminent manufacturing firm which is well known for its quality. All Microscopes are made with the latest technology so that it can provide optimum performance.\n\nWe are engaged in the manufacturing of Student Microscope and earned a good name in the international market. We also supply our product in the domestic market. We are the leading manufacturers &amp; exporters of Microscopes.<br></div>', 'Student Microscope', 'Find the Students Microscope Manufacturer, Suppliers and Exporters. Atico design and build quality based microscopes for worldwide educational use.', 'Student Microscope Manufacturer, Supplier and Exporter', 1, '2019-09-12 09:21:30', '2021-01-06 14:11:25', NULL, NULL, 1, NULL),
(156, 'Binocular Microscopes', '153', NULL, NULL, NULL, 'Binocular Microscopes', NULL, '355820binocular-microscopes-500x500.jpg', 'binocular-microscopes', 'We are <strong>manufacturer and suppliers</strong> of the entire range of <strong>Binocular Microscopes</strong>. In this device, the user can see the object clearly by using both eyes.\n\nIt is helpful to reduce eyestrain as well as muscular strain. So we make it under the instructions of skilled professionals. Our range of instruments includes all varieties of Microscopes. We have furnished the entire details of each product you may check for any equipment.\n\nWe provide products that fulfill the variegated needs of the clients. We provide innovative and superior-quality&nbsp;Science Lab Supplies&nbsp;since 1954. We have chased not only the domestic market but also covering the international market.\n\nClients, who have requirements for high-quality brand products, are suggested to contact us. Atico Export has cornered the market in the field of Science lab Instruments.\n\nWe are willing to serve you as the best <strong>Lab Microscope Manufacturer</strong>.<div bis_skin_checked=\"1\"><br><div bis_skin_checked=\"1\"><div bis_skin_checked=\"1\">As a trusted binocular microscope manufacturer, we employ advanced manufacturing techniques and cutting-edge technology to produce instruments that are at the forefront of optical excellence. Our commitment to quality ensures that each microscope is built to exacting standards, providing crisp and detailed images for precise observation and analysis.</div><div bis_skin_checked=\"1\"><br></div><div bis_skin_checked=\"1\">Our range of binocular microscopes caters to a wide spectrum of applications, from biological research and medical diagnostics to industrial quality control and educational settings. With ergonomic designs, intuitive controls, and adjustable features, our microscopes offer user-friendly experiences that optimize comfort during extended periods of use.</div><div bis_skin_checked=\"1\"><br></div><div bis_skin_checked=\"1\">We prioritize customer satisfaction and are committed to delivering unparalleled service. As a reliable supplier, we offer prompt shipping, hassle-free returns, and responsive customer support to ensure a seamless purchasing experience. Our team of experts is readily available to assist you in choosing the perfect binocular microscope that suits your needs and budget.</div></div></div>', 'Binocular Microscopes', 'Binocular microscopes manufacturers, supplier and exporters in India. Get ISO certified laboratory equipment contact us for quote', 'Binocular Microscopes Manufacturers, Supplier and Exporter In India', 1, '2019-09-12 09:21:30', '2023-07-21 12:56:21', NULL, NULL, 2, NULL);
