(283, 'Fluorescence Microscopes', '153', NULL, NULL, 0, 'Fluorescence Microscopes', NULL, '98865610581509-400x300.jpg', 'fluorescence-microscopes', 'Atico Export is the <strong>manufacturer and supplier of Fluorescence Microscopes</strong>. We serve our clients by providing them the best <strong>Lab Microscopes</strong>. We supply Microscopes to all NITs and IITs worldwide.\nWe have cornered the market since 1954 and growing day by day after its establishment. We are supplier and service provider of <strong>Lab Microscopes</strong>.\n\nAtico Export is the trademark for its quality product and other services in domestic as well as in international market. A range of Student Microscope is available here.\n\nOur suppliers deliver fast and also offers others services like less maintenance, rigid construction. We are available on social networking websites.', 'Fluorescence Microscopes', 'Fluorescence microscopes leading manufacturers, supplier and exporters in India. Get ISO certified laboratory equipment contact us for quote', 'Fluorescence Microscopes Prices, Manufacturer and Supplier In India', 1, '2019-09-12 09:21:35', '2019-11-06 18:09:12', NULL, NULL, 1, NULL),
(284, 'Stereo Microscopes', '153', NULL, NULL, NULL, 'Stereo Microscopes', NULL, '802631Stereo-Microscope-43-SMS204-250x250.jpg', 'stereo-microscopes', '<h2>Stereo Microscopes</h2><p><br></p><p>We are <strong>manufacturer and supplier of Stereo Microscopes</strong>. We sustain the growth for technology development based on our product quality.</p> \n<p>Our team, having diverse experience provides the products within the promised time frame. We offer the global range of <strong>Student Microscopes</strong></p>\n<p>To meet the required demand we focus on the quality as well as cost and durability. We not only provide the best quality as well as best services. All parts are tested under the instructions of our skilled professionals.  We are available on social networking websites also like Facebook, Twitter as well Google+. </p>	\n<p>We believe in producing the highest quality and design. Innovation in manufacturing and best maintenance services are provided  by our company. We grab the supplies of best <strong>Stereo Microscope</strong> in 30 world-wide countries. </p><p><br></p><p>Ask for details via email and chat support, drop your requirements, and message our reprehensive connect in 24 hours with details information! We believe in customer satisfaction in all aspects. Our team is committed to providing high-quality laboratory equipment at attractive prices!<br></p>', 'Stereo Microscopes', 'Stereo microscopes manufacturers, supplier and exporters in India. Trusted suppliers of lab equipment for 1954, contact us', 'Stereo Microscopes Manufacturer and Supplier In India', 1, '2019-09-12 09:21:35', '2022-05-13 18:08:43', NULL, NULL, 1, NULL),
