(347, 'Chemistry Lab Equipment', '567', NULL, NULL, 0, 'Chemistry Lab Equipment', NULL, '867736Chemistry Lab.jpg', 'chemistry-lab-equipment', '<span id=\"docs-internal-guid-1f55fb83-7fff-5e72-2f7b-40fde15ac35e\"><h2 dir=\"ltr\" style=\"line-height:1.38;margin-top:18pt;margin-bottom:6pt;\"><span style=\"font-size: 16pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\">Chemistry Lab Equipment Manufacturer</span></h2><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\">Atico Scientific is a leading name in the worldwide scientific industry. We are well-known as a leading chemistry lab equipment manufacturer for education and Industrial. Our extensive product range of chemistry lab equipment enables students, teachers, and scientists to carry out experiments with precision and accuracy. Being a consistent </span><a href=\"https://aticolabexport.com/category/chemistry-lab-equipment\"><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(17, 85, 204); background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; text-decoration-line: underline; text-decoration-skip-ink: none; vertical-align: baseline; white-space-collapse: preserve;\">chemistry lab equipment supplier</span></a><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\">, we supply the latest technology-based range of equipment to educational institutions and research laboratories for quantitative and qualitative analysis. We supply burettes, pipettes, beakers, flasks, titration apparatus, distillation sets, and other sophisticated apparatus for basic to advanced experiments in chemistry laboratories.&nbsp;</span></p><br><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\">Our laboratory equipment is designed according to international quality and safety standards to function flawlessly in the classroom as well as professional laboratories. As an internationally recognized chemistry lab equipment exporter, we take pride in equipping laboratories with cutting-edge laboratory setups manufactured with high-grade raw materials to educate students. As an ISO-certified chemistry lab equipment manufacturer, supplier, and exporter, our ability to customize equipment based on particular syllabi and local laboratory requirements is what makes laboratory professionals and teachers across the world select us.&nbsp;</span></p><br><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\">Whether to learn basic chemistry principles or to perform sophisticated experiments, our chemistry lab equipment supports an exciting and productive learning environment.&nbsp;</span></p><div><span style=\"font-size: 13pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\"><br></span></div></span>', 'Chemistry Lab Equipment, Manufacturer, Chemistry Lab Equipment Supplier, Chemistry Lab Equipment Exporter', 'Get ISO-certified chemistry lab equipment from leading manufacturer, supplier and exporter In India. At very low prices, durable and available globally. Get quote', 'Chemistry Lab Equipment Manufacturers and Suppliers In India', 1, '2019-09-12 09:22:00', '2025-04-22 08:00:52', NULL, NULL, 2, NULL),
(348, 'Food Technology', '131', 566, NULL, 0, 'Food Technology Lab Equipment, OEM manufacturers', NULL, '286777CrispManufacturing-e1526633985840.png', 'food-technology', '<div><h2>Food Technology Lab Equipment Manufacturers and Suppliers</h2><br></div>We provide huge range of <strong>Food Technology Lab Equipment</strong> in all over world. Some equipment is like; Batch Evaporation Crystallization, Batch Solid Liquid Extraction Soxhlet Batch Distillation, Climbing Film Evaporator, Refreshing Cellar, Yoghurts Drier 140 Pots and many more. Check the all product information at this page.<div><br></div><div>Ask for details via email and chat support, drop your requirements, and message our reprehensive connect in 24 hours with details information! We believe in customer satisfaction in all aspects. Our team is committed to providing high-quality laboratory equipment at attractive prices!<br></div>', 'Food Technology Lab Equipment, OEM manufacturers', 'Food Technology Lab Equipment & OEM manufacturers, suppliers and exporters in India. Atico leading science lab equipment and accessories suppliers offer best prices! Ask details', 'Food Technology Lab Equipment Manufacturers and Suppliers in India', 1, '2019-09-12 09:22:00', '2022-05-13 18:02:28', NULL, NULL, 1, NULL),
