(410, 'Sterilization Equipment', '349', NULL, NULL, 0, 'Sterilization Equipment', NULL, '841133s-l400.jpg', 'sterilization-equipment', 'Atico Export is market leader in the supply of sterile processing units because sterile environment is a necessity in most laboratories, in particular microbiology and medical labs. <strong>Sterilization</strong> refers to any process that eliminates, removes, kills, or deactivates all forms of life and other biological agents. We offer a wide variety of sterilization services and products used in research laboratories, scientific institutes’ hospitals, and pharmaceutical industry.\n\nGasket For Autoclave, High Pressure Surgical Deluxe Autoclave, Deluxe Model (triple walled with jacket), Autoclave Vertical For Laboratory, Autoclave Vertical Fully Automatic, Autoclave Vertical Semi Automatic, Table Top Autoclave (Fully Automatic), Portable Autoclave, Rectangular Horizontal Autoclave, Horizontal Cylindrical Model, Front Loading Autoclave all work to sterilize equipment and supplies. Autoclaves sterilize equipment include automatic operation, easy-close door, and pre-vacuum cycles to remove air from the chamber.\n\nAutoclaves have meters and chart that mostly used to record or display information, particularly temperature and pressure. Dry heat was the first method of sterilization, and is a longer process than moist heat sterilization.', 'Sterilization Equipment', 'Sterilization Equipment Manufacturer, Supplier. Atico India is leading Sterilization Equipment Manufacturer suppliers across the world, Contact us now for bulk order.', 'Sterilization Equipment Manufacturer, Suppliers and Exporters - Atico India', 1, '2019-09-12 09:22:01', '2019-11-06 15:56:27', NULL, NULL, 1, NULL),
(411, 'Ovens', '145', NULL, NULL, 0, 'Ovens', NULL, '881280Ovens.jpg', 'ovens', '<br>', 'Ovens', 'Ovens Manufacturer, Supplier. Atico India is leading Ovens Manufacturer suppliers across the world, Contact us now for bulk order.', 'Ovens Manufacturer, Suppliers and Exporters - Atico India', 1, '2019-09-12 09:22:01', '2019-11-06 18:40:49', NULL, NULL, 1, NULL),
(412, 'Adapters', '379', NULL, NULL, 0, 'Adapter', NULL, '9699395064690-BK000.jpg', 'adapters', '<h2>Trustable Manufacturer, Supplier, and Exporter of High Quality Adapter</h2><br>', 'Adapter', 'The team of Manufacturers at Atico design & create high quality Adapter for laboratory purposes. Contact our Supplier & Exporter to get product’s specifications.', 'Adapter Manufacturer, Supplier and Exporter', 1, '2019-09-12 09:22:01', '2021-01-06 14:24:55', NULL, NULL, 1, NULL),
(413, 'Condensers', '379', NULL, NULL, NULL, 'Condensers', NULL, '971700air-cooled-condensers-500x500.jpg', 'condensers', '<span style=\"line-height: 115%;\" calibri\",\"sans-serif\";=\"\" mso-ascii-theme-font:minor-latin;mso-fareast-font-family:calibri;mso-fareast-theme-font:=\"\" minor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-theme-font:minor-latin;=\"\" mso-ansi-language:en-in;mso-fareast-language:en-us;mso-bidi-language:ar-sa\"=\"\"><h2 style=\"font-size: 11pt; font-weight: bold;\">Condensers\nManufacturers, Suppliers and Exporters</h2><div style=\"font-size: 11pt; font-weight: bold;\"><br></div><div style=\"\"><div style=\"\"><span style=\"font-size: 14.6667px;\"><b>Explore our extensive catalog of condensers that cater to various industries and applications. As a Condensers Manufacturer and Supplier, we understand the importance of offering a diverse range to meet the unique cooling demands of different businesses. From industrial setups to commercial spaces, find the perfect condenser solution that aligns with your specific requirements.</b></span></div><div style=\"\"><span style=\"font-size: 14.6667px;\"><b><br></b></span></div><div style=\"\"><span style=\"font-size: 14.6667px;\"><b>- Tailored condenser options for different industries and applications.</b></span></div><div style=\"\"><span style=\"font-size: 14.6667px;\"><b>- Versatile solutions adaptable to various cooling needs.</b></span></div><div style=\"\"><span style=\"font-size: 14.6667px;\"><b>- High-quality products ensuring optimal performance across different sectors.</b></span></div></div></span><br><div><br></div><div><br></div>', 'Condensers', 'Atico manufactures and export laboratory Condensers that are used in distillation and reflux processes and comprise of laboratory glassware products.', 'Condensers Manufacturers, Suppliers and Exporters', 1, '2019-09-12 09:22:01', '2024-01-09 23:26:07', NULL, NULL, 2, NULL),
